var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nSN No. RS187L0005: <color=#ffd34c>에디 피셔</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>……\\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>……\\nSN No. RS187L0005：<color=#ffd34c>エディー・フィシャー</color>","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nSN No. RS187L0005: <color=#ffd34c>Eddie Fisher</color>","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nSN No. RS187L0005: <color=#ffd34c>艾迪·費舍爾</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"저희에게 필요한 인재를 찾은 것 같습니다.","JPN":"我々に必要な人材が見つかったようです。","ENG":"I believe we found the perfect talent for our company.","TWN":"我好像找到了我們需要的人才。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"A급 카운터에 관한 얘긴가?","JPN":"A級カウンターに関する話か？","ENG":"Are we talking about a Grade A Counter?","TWN":"A級制裁者嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......꿈도 크시군요. 그냥 적당한 베테랑 용병입니다.","JPN":"……高望みはよくないですよ。そこそこのベテラン傭兵です。","ENG":"Dream on. He's just a seasoned mercenary.","TWN":"……想得真美呢，只是個老手傭兵而已。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"이름은 에디 피셔. 실력과 함께 뒤탈 없는 깔끔한 일 처리로 평가가 좋은 인물입니다.","JPN":"名前はエディー・フィシャー。実力と手際の良さで、高く評価されてる人物です。","ENG":"Name's Eddie Fisher. He is a reputable person backed by great skills and a professional work ethic.","TWN":"名字是艾迪·費舍爾。實力不錯，做事乾淨俐落的高評價人物。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"동업자들 사이에선......","JPN":"同業者の間では……","ENG":"Amongst his colleagues...","TWN":"在同行之間……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"몸값을 후려치기로 유명한 악덕업주들을 상대로 오히려 돈을 뜯어낸다고 해서 <color=#ffd34c>협상가</color>란 별명으로 불리더군요.","JPN":"報酬をケチることで有名な悪徳業者を相手に金を巻き上げているので、<color=#ffd34c>ネゴシエーター</color>というあだ名で呼ばれています。","ENG":"He is known as the <color=#ffd34c>Negotiator</color> for ripping out big payments from clients notorious for being stingy.","TWN":"他會以那些打壓傭兵身價而聞名的惡德企業主為對象，\\n強行要他們吐出錢來，因此獲得了<color=#ffd34c>談判家</color>的稱號。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"하긴, 그런 친구도 있으면 좋긴 하겠군.","JPN":"まあ、そういう人がいるのも悪くない。","ENG":"Ah, it would be nice to have someone like that.","TWN":"說起來，我們如果也有這種朋友就好了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"무작정 힘으로만 부딪혀서 일을 해결하다보면 늘 뒷감당이 골치였으니 말이야.","JPN":"力任せで仕事をすると、後始末が大変だからな。","ENG":"We've always had problems cleaning up messes because our employees tend to power through their issues.","TWN":"只是胡亂地依靠力量去解決事情，這一直都讓我感到很頭痛。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그렇습니다. 작전 의뢰 보수보다 큰 피해보상 청구서 같은 건 이제 그만 보고 싶으니까요.","JPN":"ええ。作戦依頼の報酬より高額な、損害賠償請求書はもう見たくありませんので。","ENG":"I can't agree more. I don't want to see any more compensation invoices that are larger than the commission fees.","TWN":"是啊。我也不想再看到比作戰委託報酬還要多的損失賠償申請書了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"아, CSE Lv.3의 침식지대로 뛰어들어 민간인을 구출한 전력도 있군요.","JPN":"あ、CSE Lv.3の侵食地帯へ乗り込んで、民間人を救出した前歴もありますね。","ENG":"Oh, and he has a mission on his record where he rescued civilians in a CSE Lv.3 Corrupted Area.","TWN":"啊，他也有進入CESE Lv.3侵蝕地區，救助平民的戰力。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"돈이 걸린 임무 같은 것도 아니었는데 말이죠.","JPN":"報酬が出る任務でもないのに。","ENG":"Even though it was a mission he wasn't paid for.","TWN":"明明是個和錢沒有關係的任務。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그 점은 꽤 구미가 당기는군. 마냥 용병스럽지만은 않은 부분 말이야.","JPN":"傭兵らしくないな。なかなか魅力的だ。","ENG":"I like that part. He's not just a mercenary who craves money.","TWN":"那可真是讓人感興趣。這部分完全不像個傭兵呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"좀 더 자세히 알려주겠나?","JPN":"詳しく聞かせてくれ。","ENG":"Can you tell me more about him?","TWN":"你能再說得詳細一點嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"뭐, 용병스럽지 않은 선행을 한다고 해서 돈 욕심이 없었던 건 아닌가 보네요.","JPN":"傭兵らしくないとはいっても、金には目がないようです。","ENG":"Well, just because he shows some virtue, it doesn't mean that he doesn't have greed.","TWN":"這個嘛，做不像傭兵會做的事情，不代表他就不貪財。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"이상할 정도로 용병들이 꺼려하는 고위험 고보수의 임무만 골라서 수행해왔습니다.","JPN":"異常なまでに、傭兵が避けがちなハイリスク・ハイリターンな任務ばかりを選んで遂行しています。","ENG":"He has always chose high risk, high paying missions that other mercenaries avoided.","TWN":"他怪到只挑那種其他傭兵不願意去做，高風險、高報酬的任務。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"용감하군. 그렇게 벌어서 어디에 쓰는 거지?","JPN":"勇敢だな。稼いだ金は、どこにつぎ込んでるんだ？","ENG":"That's brave of him. Where is he using all of his hard earned money?","TWN":"真勇敢呢。那他賺這麼多錢，都用在哪裡了？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......몇 년 전까진 병원에서 치료비로 보수의 대부분을 썼었군요.","JPN":"……数年前までは、病院の治療費で報酬を使い果たしてました。","ENG":"He used most of his money for medical bills until a few years ago.","TWN":"……到前幾年為止，他的作戰報酬大多都花在醫院的治療費上了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그 이후로 딱히 눈에 띄는 지출은......","JPN":"その後は特に……","ENG":"After that, there hasn't been anything in particular...","TWN":"從那之後值得注意的支出……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"음? 잠깐......","JPN":"あれ……？","ENG":"Huh? Wait...","TWN":"嗯？等等……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"없어요.","JPN":"見当たりません。","ENG":"There's nothing.","TWN":"沒有了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"없다니? 뭐가 말이지?","JPN":"ん？何が見当たらないんだ？","ENG":"Nothing? What do you mean?","TWN":"沒有了？什麼沒有？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"최근 한동안 예금인출이나 지출을 한 내역이 전혀 없습니다.","JPN":"ここ最近、預金の引き出しや、支出がまったく見当たりません。","ENG":"There's no record of withdrawals or outgoing transfers recently.","TWN":"他最近一段時間，都沒有提款或支出的紀錄。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"일상 생활에 필요한 지출도 전혀 없다니, 그건 확실히 이상하군.","JPN":"日常生活の支出がないのは、確かにおかしいな。","ENG":"Not even a single daily expenditure? That is definitely strange.","TWN":"連日常生活所需的支出都沒有，這真的很奇怪。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"마지막으로 수행한 임무는 CSE Lv.2 구역의 단순정찰임무였군요.","JPN":"最後の任務は、CSE Lv.2区域の単純な偵察でした。","ENG":"His last mission was a simple scouting mission at a CSE Lv. 2 area.","TWN":"他最後執行的任務，是CSE Lv.2區域的單純偵查任務啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"여태까지 헤쳐 나온 난관들에 비하면 아무 것도 아닌 수준이었을 텐데 말이죠.","JPN":"今までの困難な任務に比べれば、大したことのない任務だったはずです。","ENG":"It should have been a cake walk compared to all his previous hurdles.","TWN":"和他至今為止克服的難關相比，應該是小意思才對啊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"아무래도 추가적인 조사가 필요할 것 같습니다.","JPN":"これは、さらなる調査が必要ですね。","ENG":"Looks like this requires further investigation.","TWN":"看來有必要做進一步調查。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......알겠네. 용병 채용 건은 잠시 보류해 두지.","JPN":"……わかった。傭兵採用の件は、しばらく保留だ。","ENG":"...Very well. We will postpone recruitment for now.","TWN":"……知道了，那雇用傭兵的事情暫時就先保留吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};